#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int **A = (int **)malloc(n * sizeof(int *));
        int **B = (int **)malloc(n * sizeof(int *));
        for (int i = 0; i < n; i++) {
            A[i] = (int *)malloc(m * sizeof(int));
            B[i] = (int *)malloc(m * sizeof(int));
        }
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                scanf("%d", &A[i][j]);
            }
        }
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                scanf("%d", &B[i][j]);
            }
        }
        int moves = 0;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                if (A[i][j] != B[i][j]) {
                    int diff = abs(A[i][j] - B[i][j]);
                    moves += diff;
                }
            }
        }
        printf("%d\n", moves);
        for (int i = 0; i < n; i++) {
            free(A[i]);
            free(B[i]);
        }
        free(A);
        free(B);
    }
    return 0;
}

