const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];

const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [n, m] = readline().split(' ').map(Number);
    const A = [];
    const B = [];
    for (let j = 0; j < n; j++) {
        A.push(readline().split(' ').map(Number));
    }
    for (let j = 0; j < n; j++) {
        B.push(readline().split(' ').map(Number));
    }
    let moves = 0;
    for (let j = 0; j < n; j++) {
        for (let k = 0; k < m; k++) {
            if (A[j][k] !== B[j][k]) {
                const diff = Math.abs(A[j][k] - B[j][k]);
                moves += diff;
            }
        }
    }
    console.log(moves);
}
